12:     this.unreadCount = 0,
13:     this.notifications = const [],
14:     this.isLoading = false,
15:     this.newSyncCount,
16:   });
17: 
18:   NotificationState copyWith({
19:     int? unreadCount,
20:     List<NotificationHistoryItem>? notifications,
21:     bool? isLoading,
22:     int? newSyncCount,
23:   }) {
24:     return NotificationState(
25:       unreadCount: unreadCount ?? this.unreadCount,
26:       notifications: notifications ?? this.notifications,
27:       isLoading: isLoading ?? this.isLoading,
28:       newSyncCount: newSyncCount ?? this.newSyncCount,
29:     );
30:   }
31: }
32: 
33: class NotificationStateNotifier extends StateNotifier<NotificationState> {
34:   NotificationStateNotifier() : super(const NotificationState()) {
35:     load();
36:   }
37: 
38:   void load() {
39:     try {
40:       final history = HiveService.getNotificationHistory();
41:       final items = history.map((json) => NotificationHistoryItem.fromJson(json)).toList();
42:       final unread = items.where((n) => !n.isRead).length;
43:       state = NotificationState(unreadCount: unread, notifications: items);
44:     } catch (e) {
45:       state = const NotificationState();
46:     }
47:   }
48: 
49:   Future<void> refresh() async {
50:     state = state.copyWith(isLoading: true);
51:     // Push notifications are now delivered in real-time via OneSignal.
52:     // Just reload from Hive to pick up any newly saved notifications.
53:     load();
54:     state = state.copyWith(isLoading: false);
55:   }
56: 
57:   Future<void> markAsRead(String id) async {
58:     await HiveService.markNotificationAsRead(id);
59:     load();
60:   }
61: 
62:   Future<void> markAllAsRead() async {
63:     await HiveService.markAllNotificationsAsRead();
64:     load();
65:   }
66: 
67:   Future<void> deleteNotification(String id) async {
68:     await HiveService.deleteNotification(id);
69:     load();
70:   }
71: 
72:   Future<void> clearAll() async {
73:     await HiveService.clearNotificationHistory();
74:     load();
75:   }
76: 
77:   /// Reloads state from Hive without triggering a Firestore sync.
