309	  /// [bigTextStyle] when provided renders an expandable rich notification.
310	  Future<void> _scheduleDailyAt({
311	    required int id,
312	    required int hour,
313	    required int minute,
314	    required String channelId,
315	    required String channelName,
316	    required String title,
317	    required String body,
318	    required bool isHighPriority,
319	    String? payload,
320	    BigTextStyleInformation? bigTextStyle,
321	  }) async {
322	    final now = tz.TZDateTime.now(tz.local);
323	    var scheduledDate = tz.TZDateTime(
324	      tz.local,
325	      now.year,
326	      now.month,
327	      now.day,
328	      hour,
329	      minute,
330	    );
331	
332	    // If the time has already passed today, schedule for tomorrow
333	    if (scheduledDate.isBefore(now)) {
334	      scheduledDate = scheduledDate.add(const Duration(days: 1));
335	    }
336	
337	    final androidDetails = AndroidNotificationDetails(
338	      channelId,
339	      channelName,
340	      channelDescription: channelName,
341	      importance: isHighPriority ? Importance.high : Importance.defaultImportance,
342	      priority: isHighPriority ? Priority.high : Priority.defaultPriority,
343	      icon: '@mipmap/ic_launcher',
344	      styleInformation: bigTextStyle, // null → default small style
345	    );
346	
347	    const iosDetails = DarwinNotificationDetails(
348	      presentAlert: true,
349	      presentBadge: true,
350	      presentSound: true,
351	    );
352	
353	    final details = NotificationDetails(
354	      android: androidDetails,
355	      iOS: iosDetails,
356	    );
357	
358	    await _plugin.zonedSchedule(
359	      id,
360	      title,
361	      body,
362	      scheduledDate,
363	      details,
364	      // Use inexactAllowWhileIdle for Doze mode compatibility
365	      androidScheduleMode: AndroidScheduleMode.inexactAllowWhileIdle,
366	      matchDateTimeComponents: DateTimeComponents.time,
367	      uiLocalNotificationDateInterpretation:
368	          UILocalNotificationDateInterpretation.absoluteTime,
369	      payload: payload,
370	    );
371	  }
