317:   /// Get the Monday of current week as "YYYY-MM-DD" string
318:   static String _getCurrentWeekStart() {
319:     final now = DateTime.now();
320:     final daysSinceMonday = now.weekday - 1;
321:     final monday = now.subtract(Duration(days: daysSinceMonday));
322:     return '${monday.year}-${monday.month.toString().padLeft(2, '0')}-${monday.day.toString().padLeft(2, '0')}';
323:   }
