325:   /// Save weekly activity map to game_progress box (for Firebase sync)
326:   static Future<void> _saveWeeklyActivityToGameProgress(Map<String, dynamic> activity) async {
327:     if (!Hive.isBoxOpen(_gameProgressBox)) return;
328:     final box = Hive.box(_gameProgressBox);
329:     final raw = box.get('user_progress');
330:     if (raw == null) return;
331:     try {
332:       final progress = GameProgressModel.fromMap(
333:         Map<String, dynamic>.from(raw as Map),
334:         '',
335:       );
336:       final updated = progress.copyWith(
337:         weeklyActivity: activity.map((k, v) => MapEntry(k, v == true)),
338:         weeklyActivityWeekStart: _getCurrentWeekStart(),
339:       );
340:       await box.put('user_progress', updated.toMap());
341:     } catch (_) {
342:       // Silently ignore parse errors
343:     }
344:   }
