346:   /// Restore weekly activity from game_progress box to settings box.
347:   /// Call this after syncing progress from Firestore to Hive.
348:   static void restoreWeeklyActivityFromProgress() {
349:     if (!Hive.isBoxOpen(_gameProgressBox)) return;
350:     final box = Hive.box(_gameProgressBox);
351:     final raw = box.get('user_progress');
352:     if (raw == null) return;
353: 
354:     try {
355:       final progress = GameProgressModel.fromMap(
356:         Map<String, dynamic>.from(raw as Map),
357:         '',
358:       );
359: 
360:       // Only restore if the stored week matches the current week
361:       if (progress.weeklyActivityWeekStart == _getCurrentWeekStart()) {
362:         final restoredMap = progress.weeklyActivity
363:             .map((k, v) => MapEntry(k, v as dynamic));
364:         _settings.put('weekly_activity', restoredMap);
365:       }
366:     } catch (_) {
367:       // Silently ignore parse errors
368:     }
369: 	  }
