371:   /// Check if the stored weekly activity is from a previous week and reset if so.
372:   /// Uses both lastPracticeDate and GameProgressModel.weeklyActivityWeekStart
373:   /// as fallback for reliable week-boundary detection.
374:   /// Should be called before markDayActive() at app start.
375:   static Future<void> resetWeeklyActivityIfNewWeek() async {
376:     if (_isNewWeek()) {
377:       await resetWeeklyActivity();
378:     }
379:   }
380: 
381:   /// Returns true if the stored weekly activity belongs to a previous week.
382:   /// Checks two sources: lastPracticeDate (settings) and weeklyActivityWeekStart (game_progress).
383:   static bool _isNewWeek() {
384:     final now = DateTime.now();
385:     final today = DateTime(now.year, now.month, now.day);
386: 
387:     // Find Monday of the current week
388:     final daysSinceMondayToday = today.weekday - 1;
389:     final mondayThisWeek = today.subtract(Duration(days: daysSinceMondayToday));
390: 
391:     // Check 1: lastPracticeDate from settings
392:     final lastPracticeDate = getLastPracticeDate();
393:     if (lastPracticeDate != null) {
394:       final lastDay = DateTime(lastPracticeDate.year, lastPracticeDate.month, lastPracticeDate.day);
395:       final daysSinceMondayLast = lastDay.weekday - 1;
396:       final mondayLastWeek = lastDay.subtract(Duration(days: daysSinceMondayLast));
397:       if (mondayLastWeek.isBefore(mondayThisWeek)) {
398:         return true;
399:       }
400:     }
401: 
402:     // Check 2: weeklyActivityWeekStart from GameProgressModel (backup)
403:     if (Hive.isBoxOpen(_gameProgressBox)) {
404:       final box = Hive.box(_gameProgressBox);
405:       final raw = box.get('user_progress');
406:       if (raw != null) {
407:         try {
408:           final progress = GameProgressModel.fromMap(
409:             Map<String, dynamic>.from(raw as Map), '');
410:           if (progress.weeklyActivityWeekStart != null &&
411:               progress.weeklyActivityWeekStart != _getCurrentWeekStart()) {
412:             return true;
413:           }
414:         } catch (_) {}
415:       }
416:     }
417: 
418:     // Also check if the settings box has weekly_activity from a different week
419:     // by looking at the stored week start (we save it alongside activity)
420:     final storedWeekStart = _settings.get('weekly_activity_week_start') as String?;
421:     if (storedWeekStart != null && storedWeekStart != _getCurrentWeekStart()) {
422:       return true;
423:     }
424: 
425:     return false;
426:   }
